import { getTasks, createTask } from "wasp/client/operations";

export function MainPage() {
  const [overdueOnly, setOverdueOnly] = useState(false);
  const [description, setDescription] = useState("");
  const [dueDate, setDueDate] = useState("");

  const { data: tasks, isLoading, error } = useQuery(getTasks, { overdueOnly });

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    if (!description.trim() || !dueDate) return;
    await createTask({ description, dueDate });
    setDescription("");
    setDueDate("");
  }

  return (
    <main style={styles.container}>
      <h1 style={styles.heading}>📋 Task Deadlines</h1>

      {/* Add Task Form */}
      <section style={styles.card}>
        <h2 style={styles.sectionTitle}>Add New Task</h2>
        <form onSubmit={handleSubmit} style={styles.form}>
          <input
            type="text"
            placeholder="Task description"
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            required
            style={styles.input}
          />
          <input
            type="datetime-local"
            value={dueDate}
            onChange={(e) => setDueDate(e.target.value)}
            required
            style={styles.input}
          />
          <button type="submit" style={styles.button}>
            Add Task
          </button>
        </form>
      </section>

      {/* Filter Toggle */}
      <section style={styles.card}>
        <label style={styles.toggleLabel}>
          <input
            type="checkbox"
            checked={overdueOnly}
            onChange={(e) => setOverdueOnly(e.target.checked)}
            style={styles.checkbox}
          />
          Show Overdue Only
        </label>
      </section>

      {/* Task List */}
      <section style={styles.card}>
        <h2 style={styles.sectionTitle}>
          {overdueOnly ? "Overdue Tasks" : "All Tasks"}
        </h2>
        {isLoading && <p style={styles.status}>Loading tasks...</p>}
        {error && <p style={styles.error}>Error: {error.message}</p>}
        {!isLoading && tasks && tasks.length === 0 && (
          <p style={styles.status}>
            {overdueOnly
              ? "No overdue tasks. You're all caught up! 🎉"
              : "No tasks yet. Add one above!"}
          </p>
        )}
        <ul style={styles.taskList}>
          {tasks &&
            tasks.map((task) => {
              const isOverdue = new Date(task.dueDate) < new Date();
              return (
                <li key={task.id} style={styles.taskItem}>
                  <div style={styles.taskDescription}>{task.description}</div>
                  <div
                    style={{
                      ...styles.taskDueDate,
                      color: isOverdue ? "#e53e3e" : "#718096",
                    }}
                  >
                    {isOverdue ? "⚠️ Overdue" : "🕐 Due"}:{" "}
                    {new Date(task.dueDate).toLocaleString()}
                  </div>
                </li>
              );
            })}
        </ul>
      </section>
    </main>
  );
}

